import { IMessageComposer } from '@nitrots/nitro-renderer';

export class HighLowAcceptComposer implements IMessageComposer<Array<number>> {
    private _data: Array<number>;

    constructor() {
        // No payload needed; just signal ACCEPT = 1
        this._data = [1];
    }

    public getMessageArray(): Array<number> {
        return this._data;
    }

    public dispose(): void {
        this._data = [];
    }
}
